import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"Course Type Overview","description":"Distinguishes undergraduate course types at SCUT, explaining whether different courses count toward GPA, weighted average, comprehensive evaluation, academic warning, and other indicators","frontmatter":{"lang":"en-US","title":"Course Type Overview","description":"Distinguishes undergraduate course types at SCUT, explaining whether different courses count toward GPA, weighted average, comprehensive evaluation, academic warning, and other indicators","llm_translated":true},"headers":[],"relativePath":"en/learn/curricular/lessons.md","filePath":"en/learn/curricular/lessons.md","lastUpdated":1784829332000}`),a={name:`en/learn/curricular/lessons.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/learn/curricular/lessons.md for this page in Markdown format</div><h1 id="course-type-overview" tabindex="-1">Course Type Overview <a class="header-anchor" href="#course-type-overview" aria-label="Permalink to “Course Type Overview”">​</a></h1><p>Course type isn&#39;t just a label game. It determines whether a course affects graduation, weighted average, GPA, comprehensive evaluation, academic warnings, major transfer, and graduate school recommendation. When looking at your course schedule, don&#39;t just glance at the course name -- check which category it falls under in your training plan.</p><h2 id="first-check-your-training-plan" tabindex="-1">First, Check Your Training Plan <a class="header-anchor" href="#first-check-your-training-plan" aria-label="Permalink to “First, Check Your Training Plan”">​</a></h2><p>The Undergraduate Handbook states that the comprehensive training plan is the basic framework for arranging teaching content, organizing teaching activities, and guiding students in course selection. It clearly specifies at least:</p><ul><li>Training objectives and graduation requirements;</li><li>Required course credits, elective course credits, and minimum graduation credits;</li><li>Course attributes, course names, class hours, credits, and teaching components;</li><li>Teaching schedule.</li></ul><p>So don&#39;t rely on word-of-mouth from upperclassmen to determine a course&#39;s type -- check your own major&#39;s and year&#39;s training plan first. The same course name in different majors may have different classifications.</p><h2 id="summary-table" tabindex="-1">Summary Table <a class="header-anchor" href="#summary-table" aria-label="Permalink to “Summary Table”">​</a></h2><table tabindex="0"><thead><tr><th>Course Type</th><th>Main Function</th><th>Affects Graduation</th><th>Counts in 100-Point Weighted Average</th><th>Counts in 4.0 GPA</th><th>Counts in Comprehensive Evaluation (Academic Score)</th></tr></thead><tbody><tr><td>Major Required Courses</td><td>Foundation for major graduation</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>Major Elective Courses</td><td>Fills major direction and elective credits</td><td>Usually</td><td>No</td><td>Yes, if required by the major training plan</td><td>May be included at department discretion</td></tr><tr><td>General Education Courses</td><td>Fills general education credits and breadth</td><td>Yes</td><td>No</td><td>No</td><td>Usually not automatically included; per department rules</td></tr><tr><td>Common Basic Courses</td><td>Math, English, Physics, PE, Political Education, etc.</td><td>Most are</td><td>Only the required ones count</td><td>Yes, if required by the major training plan</td><td>Required courses (including PE) count</td></tr><tr><td>Intensive Practice Courses</td><td>Internships, labs, training, course design, etc.</td><td>Yes</td><td>Yes if major required course</td><td>Yes if required by major training plan</td><td>Depends on grading format and department rules</td></tr><tr><td>Minor Courses</td><td>Second major, micro-major, minor degree</td><td>Only affects minor requirements</td><td>No</td><td>No</td><td>Usually not counted in major evaluation; per department rules</td></tr><tr><td>Off-Campus Courses</td><td>Cross-institutional, exchange, open courses, etc.</td><td>Credits can be recognized upon review</td><td>No</td><td>No</td><td>Usually not counted</td></tr><tr><td>Retake/Re-enroll Courses</td><td>Remedying failed courses</td><td>Credits earned upon passing</td><td>Treated as 0</td><td>Retake GPA capped at 3.3</td><td>Academic score treated as 0</td></tr></tbody></table><h2 id="required-courses-the-hardest-core" tabindex="-1">Required Courses: The Hardest Core <a class="header-anchor" href="#required-courses-the-hardest-core" aria-label="Permalink to “Required Courses: The Hardest Core”">​</a></h2><p>Required courses are those that the training plan mandates you must take and pass credits for. If you fail a major required course, you must take a retake exam or re-enroll.</p><p>Their impact is the greatest:</p><ul><li><strong>Graduation</strong>: You must earn the specified required course credits.</li><li><strong>100-point weighted average</strong>: Only calculates required courses in the major&#39;s comprehensive training plan.</li><li><strong>Major transfer and graduate recommendation</strong>: The university often directly looks at first-attempt required course scores, required course weighted average, and required course ranking.</li><li><strong>Comprehensive evaluation</strong>: The academic score is weighted from required courses (including PE) and department-selected elective courses.</li><li><strong>Awards</strong>: Having no failed courses in required courses during the academic year is usually a threshold for awards and honors.</li></ul><p>In short: required courses are the main battlefield for on-campus competition. Failing one required course doesn&#39;t just hurt during retake week -- it triggers a chain reaction across subsequent indicators.</p><h2 id="elective-courses-not-all-the-same" tabindex="-1">Elective Courses: Not All the Same <a class="header-anchor" href="#elective-courses-not-all-the-same" aria-label="Permalink to “Elective Courses: Not All the Same”">​</a></h2><p>The Undergraduate Handbook divides comprehensive training plan courses into required and elective. Electives should be viewed in two categories:</p><ul><li><strong>Major elective courses</strong>: Usually used to fulfill direction or module requirements within your major. Graduation conditions require a specified number of credits.</li><li><strong>General education courses</strong>: Part of the common basic general education, covering humanities, social sciences, science and technology, etc.</li></ul><p>The key point about electives isn&#39;t whether they&#39;re “easy” -- it&#39;s whether they&#39;re required by the training plan and whether the department includes them in a given indicator.</p><ul><li><strong>100-point weighted average</strong>: Not counted. The handbook clearly states this only covers major required courses.</li><li><strong>4.0 GPA</strong>: Major elective courses are usually included if required by the major&#39;s training plan; general education courses are not.</li><li><strong>Comprehensive evaluation academic score</strong>: Required courses are always included; whether electives are included is up to each department.</li></ul><h2 id="common-basic-courses-common-name-not-so-common-consequences" tabindex="-1">Common Basic Courses: Common Name, Not-So-Common Consequences <a class="header-anchor" href="#common-basic-courses-common-name-not-so-common-consequences" aria-label="Permalink to “Common Basic Courses: Common Name, Not-So-Common Consequences”">​</a></h2><p>Common basic courses include social science basics, natural science basics, skill-oriented basics (required and general education). Common examples: Math, English, Physics, PE, Political Education, Military Theory.</p><p>Don&#39;t misunderstand “common” as “unimportant.” Many major transfer thresholds directly target math, English, physics, and other common basics. The comprehensive evaluation also explicitly includes PE in the required course academic score.</p><p>The judgment is simple: if a common basic course is a required course in your training plan, treat it as a required course; if it&#39;s a general education course, treat it as such.</p><h2 id="minor-courses-mostly-ignored-by-major-indicators" tabindex="-1">Minor Courses: Mostly Ignored by Major Indicators <a class="header-anchor" href="#minor-courses-mostly-ignored-by-major-indicators" aria-label="Permalink to “Minor Courses: Mostly Ignored by Major Indicators”">​</a></h2><p>Minor programs, minor bachelor&#39;s degrees, and micro-majors are additional systems pursued on top of completing your major requirements.</p><p>Key rules:</p><ul><li>Minor courses are recorded under the minor teaching plan and affect the minor certificate or degree;</li><li>They do not count toward the major&#39;s 100-point weighted average;</li><li>They do not count toward the 4.0 GPA;</li><li>Failed or unsatisfactory minor courses can be dropped and retaken;</li><li>Students who apply to defer major courses are not eligible for minor programs.</li></ul><p>The value of a minor lies in skills and experience, not boosting your major GPA. Using minor courses to gamble on major indicators is misreading the ledger.</p><h2 id="off-campus-courses-credits-can-be-recognized-grades-don-t-count" tabindex="-1">Off-Campus Courses: Credits Can Be Recognized, Grades Don&#39;t Count <a class="header-anchor" href="#off-campus-courses-credits-can-be-recognized-grades-don-t-count" aria-label="Permalink to “Off-Campus Courses: Credits Can Be Recognized, Grades Don&#39;t Count”">​</a></h2><p>Students can take courses at other institutions through inter-university exchange agreements. After review by the Academic Affairs Office, off-campus course grades and credits are recorded on the transcript with an “off-campus” designation, and can be recognized toward SCUT credits as per regulations.</p><p>But the handbook is strict: <strong>Off-campus course grades and credits are never included in any type of GPA calculation</strong>.</p><p>This means:</p><ul><li>They can be used for credit recognition;</li><li>They can appear on your transcript;</li><li>They do not count toward the 100-point weighted average;</li><li>They do not count toward the 4.0 GPA.</li></ul><p>Off-campus courses are good for gaining experience, earning credits, and doing exchanges -- not for saving your GPA.</p><h2 id="retake-re-enroll-deferred-exam-deferred-study" tabindex="-1">Retake, Re-enroll, Deferred Exam, Deferred Study <a class="header-anchor" href="#retake-re-enroll-deferred-exam-deferred-study" aria-label="Permalink to “Retake, Re-enroll, Deferred Exam, Deferred Study”">​</a></h2><p>These terms are the easiest to confuse:</p><table tabindex="0"><thead><tr><th>Situation</th><th>Nature</th><th>Impact on Indicators</th></tr></thead><tbody><tr><td>Retake Exam</td><td>If you fail the first attempt, you take the exam arranged by the offering department at the start of the next semester</td><td>100-point average treated as 0; GPA retake range capped at 3.3; comprehensive evaluation academic score treated as 0</td></tr><tr><td>Re-enroll</td><td>Retake the course and sit for assessment again</td><td>100-point average treated as 0; comprehensive evaluation academic score treated as 0; noted on transcript</td></tr><tr><td>Deferred Exam</td><td>Approved postponement due to illness or schedule conflict before the exam</td><td>Not recorded as a retake; if passed, can be counted toward the corresponding semester&#39;s indicators per rules</td></tr><tr><td>Deferred Study</td><td>Approved postponement of some major courses due to learning difficulties</td><td>If passed, can be counted toward the study semester; those applying for deferred study cannot participate in minor programs</td></tr></tbody></table><p>Core difference: Retake/re-enroll are remedies after failure; deferred exam/study are approved postponements. The former already damage first-attempt indicators; the latter still have room for normal recording under the rules.</p><h2 id="relationship-with-key-indicators" tabindex="-1">Relationship with Key Indicators <a class="header-anchor" href="#relationship-with-key-indicators" aria-label="Permalink to “Relationship with Key Indicators”">​</a></h2><h3 id="_100-point-weighted-average" tabindex="-1">100-Point Weighted Average <a class="header-anchor" href="#_100-point-weighted-average" aria-label="Permalink to “100-Point Weighted Average”">​</a></h3><p>Used for on-campus graduate recommendation, major transfer, etc. The calculation scope is <strong>required courses in the major&#39;s comprehensive training plan</strong>, based on first-attempt scores. Failed, not-passed, re-enroll-passed, and retake-passed courses are treated as 0.</p><h3 id="_4-0-gpa" tabindex="-1">4.0 GPA <a class="header-anchor" href="#_4-0-gpa" aria-label="Permalink to “4.0 GPA”">​</a></h3><p>Mainly used for study-abroad grade certificates, etc. The calculation scope is <strong>courses required by the major&#39;s comprehensive training plan</strong>, but general education courses, minor courses, and off-campus courses are not included. Based on the highest course grade achieved. Retake GPA is capped at 3.3.</p><h3 id="comprehensive-evaluation-academic-score" tabindex="-1">Comprehensive Evaluation Academic Score <a class="header-anchor" href="#comprehensive-evaluation-academic-score" aria-label="Permalink to “Comprehensive Evaluation Academic Score”">​</a></h3><p>The comprehensive evaluation academic score is calculated as the weighted average of the year&#39;s required courses (including PE) and department-selected elective courses, converted to a 100-point scale. Whether electives count -- don&#39;t guess, check your department&#39;s detailed rules.</p><h3 id="academic-warning" tabindex="-1">Academic Warning <a class="header-anchor" href="#academic-warning" aria-label="Permalink to “Academic Warning”">​</a></h3><p>When academic warnings tally accumulated failed credits, general education courses, minor courses, and off-campus courses are excluded; credits previously earned through retakes or re-enrollment count as passed; retake scores from the current semester&#39;s start are not included in the calculation.</p><h2 id="quick-judgment-method" tabindex="-1">Quick Judgment Method <a class="header-anchor" href="#quick-judgment-method" aria-label="Permalink to “Quick Judgment Method”">​</a></h2><p>When looking at a course, follow this order:</p><ol><li>Is it in your major&#39;s training plan?</li><li>Is it required, major elective, general education, or practice?</li><li>Is it first-attempt, deferred, or retake/re-enroll?</li><li>What do you care about -- graduation, weighted average, GPA, comprehensive evaluation, or academic warning?</li></ol><p>Don&#39;t ask “does this course count toward my grades?” That&#39;s too vague. Ask: <strong>as what course type, and toward which indicator, does this course count?</strong></p><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to “References”">​</a></h2><p>The following references are from the <a href="/assets/pdf/scut_undergraduate_handbook_2024.pdf">Undergraduate Handbook (PDF)</a> (2024 Undergraduate Handbook). Page numbers use PDF reader pagination; numbers in parentheses are the handbook header page numbers. Course type, training plan, and indicator calculations may be adjusted by year, campus, departmental rules, or new university policies. For actual course selection, credit recognition, major transfer, graduate recommendation, awards, and academic warnings, refer to the latest notices from the university, Academic Affairs Office, Student Affairs Office, and your specific school/department.</p><ul><li>PDF pp. 60-61 (Handbook pp. 58-59), SCUT Full-Time Undergraduate Credit System Teaching Management Implementation Measures (2017 Revision), Parts 1, 2, and 3: Basic framework for credit system, comprehensive training plan, minimum graduation credits, required/elective credits, course attributes, common basic courses, disciplinary basic courses, specialized courses, intensive practice courses, and general education courses.</li><li>PDF pp. 67-69 (Handbook pp. 65-67), same measures, Chapters 5 and 6: Course offerings divided into required and elective; students should prioritize major required courses; deferred study, general education course selection, minor courses, course exemption, audit exemption, retake, deferred exam, re-enrollment, grade recording, off-campus course classification and credit/GPA treatment.</li><li>PDF pp. 70-71 (Handbook pp. 68-69), same measures, Article 39: 100-point weighted average only calculates major required courses; 4.0 GPA calculates courses required by the major&#39;s comprehensive training plan, excluding general education, minor, and off-campus courses.</li><li>PDF p. 77 (Handbook p. 75), SCUT Full-Time Undergraduate Bachelor&#39;s Degree Award Implementation Rules, Chapter 2, Article 4, Item 5: Bachelor&#39;s degree requirement of 4.0 GPA ≥ 2.0, excluding minor and off-campus courses.</li><li>PDF p. 100 (Handbook p. 98), SCUT Full-Time Undergraduate Minor Program and Minor Bachelor&#39;s Degree Implementation Rules, Articles 7, 10-15: Minor registration conditions, minor course teaching plan and grade management, minor course failure handling, suspension of minor eligibility under academic warning, and credit recognition rules upon termination of minor.</li><li>PDF p. 160 (Handbook p. 158), SCUT Full-Time Undergraduate On-Campus Credit Recognition Implementation Measures, Articles 4, 5, and 6: Credit recognition between minor/micro-major courses and general education or non-major elective courses, and the limitation that “credit recognition is only for graduation eligibility review.”</li><li>PDF pp. 168-169 (Handbook pp. 166-167), SCUT Full-Time Undergraduate Academic Warning and Grade Reduction Trial Implementation Measures (2020 Revision), Parts 2 and 3: Academic warning tallying of accumulated failed credits, excluding general education, minor, and off-campus courses; statistical treatment of credits earned through retakes/re-enrollment and current-semester retake scores.</li><li>PDF p. 202 (Handbook p. 200), SCUT Undergraduate Comprehensive Evaluation and Awards Measures (2023 Revision), Appendix 1: Comprehensive evaluation academic score calculated as weighted average of required courses (including PE) and department-selected elective course grades on a 100-point scale.</li></ul>`,54)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};